+/** Options for loading command configuration. */
+export interface ConfigOptions {
+  /** Base name of the configuration file, without its extension. */
+  name: string;
+  /** Directories searched for configuration files. */
+  searchPaths?: string[];
+  /** File extensions to search, in order. */
+  formats?: string[];
+  /** Merge files from every search path instead of using the first match. */
+  mergeConfigs?: boolean;
+  /** Custom parser for configuration file contents. */
+  parser?: (content: string) => Record<string, unknown>;
+}
+
+/** Thrown when a configuration file cannot be parsed. */
+export class ConfigParseError extends Error {
+  constructor(path: string, cause?: unknown) {
+    super(`Failed to parse config file "${path}".`, { cause });
+    Object.setPrototypeOf(this, ConfigParseError.prototype);
+  }
+}
+
+/** Thrown when a configuration value does not match its option type. */
+export class ConfigValidationError extends Error {
+  constructor(key: string, expected: string) {
+    super(`Invalid config value for "${key}". Expected ${expected}.`);
+    Object.setPrototypeOf(this, ConfigValidationError.prototype);
+  }
+}
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths ?? [Deno.cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const matches: Array<{ path: string; values: Record<string, unknown> }> = [];
+
+  for (const directory of paths) {
+    for (const format of formats) {
+      const path = `${directory.replace(/[\\\\/]$/, "")}/${options.name}${format}`;
+      try {
+        const content = await Deno.readTextFile(path);
+        matches.push({ path, values: parseConfig(content, path, format, options.parser) });
+        break;
+      } catch (error) {
+        if (error instanceof Deno.errors.NotFound) continue;
+        if (error instanceof ConfigParseError) throw error;
+        throw error;
+      }
+    }
+    if (matches.length && !options.mergeConfigs) break;
+  }
+
+  // Earlier search paths win, as documented.
+  const values = matches.reduceRight<Record<string, unknown>>(
+    (result, config) => ({ ...result, ...flattenConfig(config.values) }),
+    {},
+  );
+  return { path: matches[0]?.path, values };
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  format: string,
+  parser?: (content: string) => Record<string, unknown>,
+): Record<string, unknown> {
+  try {
+    const value = parser ? parser(content) : format === ".rc" ? parseRc(content) : JSON.parse(content);
+    if (!value || typeof value !== "object" || Array.isArray(value)) throw new TypeError("Config must be an object");
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index < 1) throw new TypeError("Invalid RC entry");
+    const key = trimmed.slice(0, index).trim();
+    let value = trimmed.slice(index + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) value = value.slice(1, -1);
+    values[key] = value === "true" ? true : value === "false" ? false : value !== "" && !Number.isNaN(Number(value)) ? Number(value) : value;
+  }
+  return values;
+}
+
+/** Flatten nested object keys while preserving arrays as option values. */
+export function flattenConfig(values: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  return Object.entries(values).reduce<Record<string, unknown>>((result, [key, value]) => {
+    const name = `${prefix}${key}`.replace(/-([a-z])/g, (_, char: string) => char.toUpperCase());
+    if (value && typeof value === "object" && !Array.isArray(value)) {
+      Object.assign(result, flattenConfig(value as Record<string, unknown>, `${name}.`));
+    } else result[name] = value;
+    return result;
+  }, {});
+}
