+async function configDir(files: Record<string, string>): Promise<string> {
+  const dir = await Deno.makeTempDir();
+  await Promise.all(Object.entries(files).map(([name, value]) => Deno.writeTextFile(`${dir}/${name}`, value)));
+  return dir;
+}
+
+test("command: loads JSON config and applies CLI precedence", async () => {
+  const dir = await configDir({ "app.json": '{"port": 0, "verbose": false, "db": {"host": "localhost"}}' });
+  const cmd = new Command().throwErrors()
+    .config({ name: "app", searchPaths: [dir] })
+    .option("--port <port:number>", "...")
+    .option("--verbose", "...")
+    .option("--db.host <host>", "...");
+  const result = await cmd.parse(["--port", "3000"]);
+  assertEquals(result.options, { port: 3000, verbose: false, db: { host: "localhost" } });
+  assertEquals(cmd.getConfigPath(), `${dir}/app.json`);
+  assertEquals(cmd.getConfigValues(), { port: 0, verbose: false, "db.host": "localhost" });
+});
+
+test("command: environment values override config", async () => {
+  const dir = await configDir({ "app.json": '{"port": 1}' });
+  const cmd = new Command().throwErrors()
+    .config({ name: "app", searchPaths: [dir] })
+    .env("PORT=<value:number>", "...")
+    .option("--port <port:number>", "...");
+  Deno.env.set("PORT", "2");
+  try {
+    assertEquals((await cmd.parse([])).options, { port: 2 });
+  } finally {
+    Deno.env.delete("PORT");
+  }
+});
+
+test("command: loads RC config and merges paths with earlier precedence", async () => {
+  const first = await configDir({ ".apprc": '# comment\
